const payload = $input.first().json;
const row = payload?.data?.[0] || payload;

const ignore = new Set([
  'id', 'user_id', 'created_at', 'updated_at', 'canvas', 'metadata'
]);

const mapped = Array.isArray(row?.metadata?.canvas_sections)
  ? row.metadata.canvas_sections
  : [];

const sections = Object.entries(row)
  .filter(([key, val]) => !ignore.has(key))
  .filter(([_, val]) => val !== null && val !== '' && !(Array.isArray(val) && val.length === 0))
  .filter(([key]) => !mapped.includes(key))
  .map(([key, val]) => ({
    key,
    label: key.replace(/_/g, ' ').toUpperCase(),
    content: val
  }));

return [{
  json: {
    projectId: row.id,
    sections,
    existingCanvas: row.canvas || { elements: [], appState: {}, files: {} },
    metadata: row.metadata || {},
    mapped
  }
}];

const generated = $input.first().json;
const prior = $node['Build Canvas Sections'].json;

const existing = prior.existingCanvas || { elements: [], appState: {}, files: {} };
const localElements = Array.isArray(existing.elements) ? existing.elements : [];
const newElements = Array.isArray(generated.elements) ? generated.elements : [];

const map = new Map(localElements.map(el => [el.id, el]));
const merged = [...localElements];
for (const el of newElements) {
  if (el?.id && !map.has(el.id)) merged.push(el);
}

const newKeys = prior.sections.map(s => s.key);
const updatedMetadata = {
  ...prior.metadata,
  canvas_sections: Array.from(new Set([...(prior.mapped || []), ...newKeys]))
};

return [{
  json: {
    projectId: prior.projectId,
    canvas: { ...existing, elements: merged },
    metadata: updatedMetadata
  }
}];
